class Solution:
    def removeKdigits(self, num: str, k: int) -> str:
        st = []
        for ch in num:
            while k and st and st[-1] > ch:
                st.pop(); k -= 1
            st.append(ch)
        st = st[:len(st)-k] if k else st
        return ("".join(st).lstrip("0") or "0")

