class Solution {
public:
    string removeKdigits(string num, int k) {
        string st;
        for (char ch : num) {
            while (k && !st.empty() && st.back() > ch) { st.pop_back(); k--; }
            st.push_back(ch);
        }
        if (k) st.resize(st.size() - k);
        size_t i = st.find_first_not_of('0');
        return i == string::npos ? "0" : st.substr(i);
    }
};

