char* removeKdigits(char* num, int k) {
    int n = strlen(num), top = 0;
    char* st = malloc(n + 2);
    for (int i = 0; i < n; i++) {
        while (k && top && st[top-1] > num[i]) { top--; k--; }
        st[top++] = num[i];
    }
    top -= k; if (top < 0) top = 0;
    int s = 0; while (s < top && st[s] == '0') s++;
    if (s == top) { st[0]='0'; st[1]=0; return st; }
    memmove(st, st+s, top-s+1);
    return st;
}
